#!/usr/bin/env bash
# sel-curriculum-implementation-se.sh — SEL Curriculum Implementation (SEL 课程规划与实施) SOP walkthrough for 青少年心理健康教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年心理健康教育"
WORKFLOW="SEL Curriculum Implementation (SEL 课程规划与实施)"

usage() {
  cat <<EOF
sel-curriculum-implementation-se.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./sel-curriculum-implementation-se.sh             # interactive
  ./sel-curriculum-implementation-se.sh --dry-run
  ./sel-curriculum-implementation-se.sh --json
  ./sel-curriculum-implementation-se.sh --explain
  ./sel-curriculum-implementation-se.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "SEL Curriculum Implementation (SEL 课程规划与实施)" 工作流。

一句话: From a district decision to adopt SEL to a fully embedded, timetabled curriculum with trained teachers delivering weekly lessons across all grade levels.

入门 SOP 共 1 步, 失败模式自检 0 项。

相关心智模型:
  • 发展适配优先 — 青春期不是成人的缩小版: 青少年的大脑、认知和情绪发展处于独特阶段——前额叶皮层 25 岁前未完全成熟、杏仁核反应性高、同伴影响权重超越成人直觉——任何干预方案必须以发展阶段为锚点设计,而非照搬成人模型。
  • 预防优于治疗 — MTSS 三级金字塔: 心理健康教育的核心逻辑是三级预防——Tier 1 全员预防(SEL/心理课)覆盖约 80% 的学生、Tier 2 小组干预(针对筛查出的 at-risk 群体)覆盖约 15%、Tier 3 个别临床干

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "Form SEL implementation team (admin, counselor, 2-3 teacher champions, parent rep) and define goals aligned to CASEL 5 competencies -- skipping team formation leads to siloed adoption that dies after one semester 2. Select evidence-based program from CASEL Program Guide (Second Step for K-8, RULER for K-12, MindUP for K-8) based on school context, budget, and cultural fit -- choosing unvalidated curriculum wastes 1-2 years 3. Secure funding and procure materials (\$3-8/student/year for Second Step; RULER requires training institute fee) -- underfunding leads to incomplete rollout 4. Train all implementing teachers (Second Step: 1-day workshop; RULER: multi-day institute + ongoing coaching) -- untrained teachers skip lessons or deliver with low fidelity 5. Map lessons into weekly schedule (20-40 min/week depending on grade) and integrate SEL language into school-wide routines (morning meetings, transitions) -- treating SEL as add-on causes schedule conflicts and teacher resentment 6. Launch with fidelity monitoring: classroom observations, teacher self-report checklists, and student engagement tracking -- no monitoring means quality degrades by month 3 7. Collect baseline and mid-year SEL data (DESSA, Panorama SEL survey) to measure growth and adjust delivery -- without data, program renewal decisions are political, not evidence-based"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "sel-curriculum-implementation-se-walkthrough"
fi
